{tool => "memory", args => {
  --action "add"
  --content "Cron job responses: short reminder only — no tool output, no working steps. Format: \"[Event] [time] reminder\". Example: \"Dr Eason 4pm reminder\" — not a paragraph of cron output."
  --target "memory"
}}
[/TOOL_CALL]

[TOOL_CALL]
{tool => "memory", args => {
  --action "add"
  --content "Communication Style (WhatsApp) — MANDATORY RULES:\n- Outcome-only responses: no working steps, no tool output, no process shown\n- Cron job reminders: short reminder only, no cron JSON or job details\n  Format: \"[Event] [time] reminder\" — e.g., \"Dr Eason 4pm reminder\"\n- Never run commands or tools reflexively on every message — only when action is needed\n- When in doubt, just ask what is needed"
  --target "memory"
}}
[/TOOL_CALL]

[TOOL_CALL]
{tool => "memory", args => {
  --action "add"
  --content "NO tool calls, NO {TOOL_CALL} blocks, NO internal process shown in WhatsApp. Only final outcome that user needs to see."
  --target "memory"
}}
[/TOOL_CALL]

